import type { DialogueEntry } from '../../../types';
import { CharacterId } from '../characters';
import { Portrait } from '../portraits';
import { Background } from '../backgrounds';

export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "邵叔走在前面，腳步不快不慢，像帶自家小孩去診所看病。顧言跟在後面，兩手插在校服口袋裡，沒有說話。南翼走廊比主樓安靜很多。牆壁上貼著防颱須知和緊急疏散路線圖，每隔幾步就有一盞應急燈。", background: Background.Chapter_3_Ch3_Act9_S0 },
    { characterId: CharacterId.ShaoQiming, character: "邵啟明", dialogue: "到了。", background: Background.Chapter_3_Ch3_Act9_S0, portrait: Portrait.ShaoQiming_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "邵叔在一扇木門前停下來。門上掛著一塊白色牌子：南翼醫務室。牌子下面貼了一張手寫的紙條，字跡工整——「防颱期間，如有不適請直接入內」。", background: Background.Chapter_3_Ch3_Act9_S0 },
    { characterId: CharacterId.ShaoQiming, character: "邵啟明", dialogue: "保健老師今天值班。我已經打過招呼了。", background: Background.Chapter_3_Ch3_Act9_S0, portrait: Portrait.ShaoQiming_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "⋯⋯嗯。", background: Background.Chapter_3_Ch3_Act9_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "邵叔推開門，回頭看了他一眼。那個眼神裡有點什麼，不是擔心，比較像確認——確認他沒有跑掉的念頭。", background: Background.Chapter_3_Ch3_Act9_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "外間不大。一張辦公桌，桌上攤著登記簿和一支黑色原子筆。桌角有一台舊式電話，聽筒擱在座上，燈亮著。左手邊牆上釘著白色藥櫃，櫃門上貼了分類標籤。右手邊是一張折疊椅和一個不銹鋼污物桶。", background: Background.Chapter_3_Ch3_Act9_S1 },
    { characterId: CharacterId.HealthTeacher, character: "保健老師", dialogue: "顧言同學？邵警官跟我說了。你先坐，我幫你倒杯水。", background: Background.Chapter_3_Ch3_Act9_S1, portrait: Portrait.HealthTeacher_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "不用。", background: Background.Chapter_3_Ch3_Act9_S1, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.HealthTeacher, character: "保健老師", dialogue: "那進去裡面躺著吧，裡面安靜。", background: Background.Chapter_3_Ch3_Act9_S1, portrait: Portrait.HealthTeacher_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "保健老師三十出頭，頭髮紮成低低的髻，護士服上別著校徽。她的表情溫和而疲倦，像今天已經接待過太多人。她從桌後走出來，推開了通往內間的門。", background: Background.Chapter_3_Ch3_Act9_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "內間比外間更安靜。兩張病床並排放著，床單雪白，枕頭整整齊齊。遠端的牆上有兩扇磨砂玻璃窗，窗面上貼著灰色的防颱膠帶，從左上到右下、左下到右上，交疊成一個歪歪的十字。窗外側加了半高的防颱板，把視線攔腰截斷，只剩上方一小截透出灰白的天光。", background: Background.Chapter_3_Ch3_Act9_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "窗戶上方，靠近天花板的位置，有一排舊式通風百葉。葉片很窄，間距很密，隱約能看見外面有什麼東西被風吹得一鼓一鼓的——塑膠布，或者防颱用的遮蓋材料。", background: Background.Chapter_3_Ch3_Act9_S2 },
    { characterId: CharacterId.ShaoQiming, character: "邵啟明", dialogue: "你先躺一會兒。", background: Background.Chapter_3_Ch3_Act9_S2, portrait: Portrait.ShaoQiming_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "邵叔跟進來，兩手背在身後，環顧了一圈內間。他的目光掃過窗戶、通風口、病床，然後落回顧言身上。", background: Background.Chapter_3_Ch3_Act9_S2 },
    { characterId: CharacterId.ShaoQiming, character: "邵啟明", dialogue: "這裡離指揮區近，有事我馬上過來。南翼今天人少，校安會在走廊巡。保健老師全天值班。你就當休息。", background: Background.Chapter_3_Ch3_Act9_S2, portrait: Portrait.ShaoQiming_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)他在替我數。每說一個理由，就像在替這個房間加一道鎖。", background: Background.Chapter_3_Ch3_Act9_S2, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)保健老師值班。校安巡邏。離指揮區近。南翼人少。每一條都合理。每一條都讓這個房間變得更「安全」。每一條都讓我更不容易離開。", background: Background.Chapter_3_Ch3_Act9_S2, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "⋯⋯好。", background: Background.Chapter_3_Ch3_Act9_S2, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.ShaoQiming, character: "邵啟明", dialogue: "你不是犯人，是需要保護的人。先待在這裡，等我把監控和車輛查完。", background: Background.Chapter_3_Ch3_Act9_S2, portrait: Portrait.ShaoQiming_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)保護。", background: Background.Chapter_3_Ch3_Act9_S2, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)這兩個字。", background: Background.Chapter_3_Ch3_Act9_S2, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)被保護起來，不代表安全。也可能只是比較好找。", background: Background.Chapter_3_Ch3_Act9_S2, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠的聲音像一根細針，從記憶裡刺過來。顧言站在病床邊，沒有坐下。他看著邵叔的背影，看著他走出去之前最後一次回頭的樣子——那個回頭很自然，像父親出門前確認孩子有沒有蓋好被子。", background: Background.Chapter_3_Ch3_Act9_S2 },
    { characterId: CharacterId.ShaoQiming, character: "邵啟明", dialogue: "水在桌上。不舒服就叫老師。", background: Background.Chapter_3_Ch3_Act9_S2, portrait: Portrait.ShaoQiming_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "門關上了。腳步聲沿走廊遠去。", background: Background.Chapter_3_Ch3_Act9_S2 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)他走了。", background: Background.Chapter_3_Ch3_Act9_S2, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言沒有躺下。他站在內間中央，開始看這個房間。", background: Background.Chapter_3_Ch3_Act9_S2 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)認識你的籠子，才有機會逃出去。", background: Background.Chapter_3_Ch3_Act9_S2, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他先走到窗邊。磨砂玻璃讓外面的世界變成一片模糊的灰。他伸手摸了摸窗框上的灰色防颱膠帶。質地很粗糙，邊緣有不規則的撕裂痕，像被倉促裁剪後直接貼上去的。", background: Background.Chapter_3_Ch3_Act9_S2 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)灰色膠帶。", background: Background.Chapter_3_Ch3_Act9_S2, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)第一輪。鐘樓臨時告示邊角，同樣的灰色膠帶。第二輪。裝卸區器材箱封條旁邊，同樣的灰色。現在。醫務室窗戶。", background: Background.Chapter_3_Ch3_Act9_S2, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)三個地方。同一種膠帶。不是巧合。是同一批人貼的。", background: Background.Chapter_3_Ch3_Act9_S2, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他轉身走向內間和外間之間的門框，探頭看了一眼外間。保健老師坐在桌前，正翻著登記簿，低頭在寫什麼。她的背影很安靜，肩膀微微前傾，是長期伏案的人才有的姿勢。", background: Background.Chapter_3_Ch3_Act9_S2 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)她不是壞人。她只是一個今天被安排值班的老師。", background: Background.Chapter_3_Ch3_Act9_S2, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他的目光落在桌上攤開的登記簿上。保健老師剛翻到新的一頁，但前一頁還露著一半。他看見幾行字——不是病患紀錄，是物品借用登記。倒數第三行寫著：", background: Background.Chapter_3_Ch3_Act9_S2 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)「南翼備用門禁卡：行政組借用，醫療動線確認，已歸還。」", background: Background.Chapter_3_Ch3_Act9_S2, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)門禁卡。", background: Background.Chapter_3_Ch3_Act9_S2, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)行政組借了南翼備用門禁卡。用途是「醫療動線確認」。已經歸還了。這意味著——曾經有一段時間，有人拿著能開這扇門、開這整條走廊的卡，在外間走動過。", background: Background.Chapter_3_Ch3_Act9_S2, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)而且是「醫療動線」。不是「設備檢修」，不是「安全巡邏」。是「醫療」。這個房間所在的動線，早就被人走過了。", background: Background.Chapter_3_Ch3_Act9_S2, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他收回目光，退回內間。保健老師沒有抬頭。", background: Background.Chapter_3_Ch3_Act9_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他走向內間最深處，那扇他剛進來就注意到的門。後門。比正門窄，漆成和牆壁接近的灰白色，門把是老式的壓把鎖，金屬表面有鏽跡。門上貼著一張紅底白字的貼紙，四個角用膠帶加固：", background: Background.Chapter_3_Ch3_Act9_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "防颱期間勿開。", background: Background.Chapter_3_Ch3_Act9_S2 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)後門。通向設備平台。平常鎖著。防颱期間更不能開。", background: Background.Chapter_3_Ch3_Act9_S2, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)這扇門的另一邊是什麼？設備平台。外牆。通風口。", background: Background.Chapter_3_Ch3_Act9_S2, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)這個房間有兩個出口。走廊門通往南翼走廊，後門通往設備平台。正門需要經過外間、經過保健老師。後門——被防颱規定鎖死。", background: Background.Chapter_3_Ch3_Act9_S2, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)一個出口有人看著。一個出口被規定封著。", background: Background.Chapter_3_Ch3_Act9_S2, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他沒有碰後門的門把。他轉過身，抬頭看天花板附近的那排通風百葉。葉片是金屬的，表面有薄薄的灰。百葉外面的塑膠布被風吹得一下一下拍在葉片上，發出很輕的、不規律的啪嗒聲。", background: Background.Chapter_3_Ch3_Act9_S2 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)通風口外側有塑膠布。雨水打在上面，風把布吹向百葉。空氣——", background: Background.Chapter_3_Ch3_Act9_S2, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他深吸了一口。空氣沒有什麼特別。消毒水的味道，床單的漿洗味，一點點悶。但能呼吸。", background: Background.Chapter_3_Ch3_Act9_S2 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)現在沒問題。但通風百葉外面有東西擋著。如果外面的風向改了，如果塑膠布貼得更緊——", background: Background.Chapter_3_Ch3_Act9_S2, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)不。不要想那麼遠。現在是下午一點半。離晚上還有很長時間。邵叔在查監控。鐘樓會封。校務車會停。這一輪的路線是不一樣的。", background: Background.Chapter_3_Ch3_Act9_S2, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他走到靠裡面那張病床邊，慢慢坐下。床墊偏硬，床單有漿洗過的脆感。他把手機放在枕頭旁邊，兩手撐在床沿，低著頭。", background: Background.Chapter_3_Ch3_Act9_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "外間傳來保健老師翻頁的聲音。很輕。像翻一本很薄的日記。走廊上偶爾有腳步聲經過，不會停。", background: Background.Chapter_3_Ch3_Act9_S2 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)這個房間。", background: Background.Chapter_3_Ch3_Act9_S2, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)保健老師在門外。校安在走廊。窗戶貼了防颱膠帶。後門鎖了。通風口外面有塑膠布。", background: Background.Chapter_3_Ch3_Act9_S2, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)所有的一切都指向同一個結論：你很安全。乖乖待著。", background: Background.Chapter_3_Ch3_Act9_S2, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)但我就是不放心。", background: Background.Chapter_3_Ch3_Act9_S2, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)許星棠說的。「被保護起來，不代表安全。也可能只是比較好找。」", background: Background.Chapter_3_Ch3_Act9_S2, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)我被放進了一個很好找的地方。門禁卡被行政組借過。灰色膠帶和鐘樓是同一批。通風口外面不知道有什麼。", background: Background.Chapter_3_Ch3_Act9_S2, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)⋯⋯", background: Background.Chapter_3_Ch3_Act9_S2, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)先不想。先觀察。邵叔真的在查。我等到結果出來再判斷。", background: Background.Chapter_3_Ch3_Act9_S2, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他向後躺下去。枕頭偏薄，頸椎懸空了一截。他盯著天花板。日光燈管發出細微的嗡鳴聲，光是白色的，冷，均勻，沒有任何死角。", background: Background.Chapter_3_Ch3_Act9_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "窗外，雨聲不變。通風百葉的塑膠布還在拍。啪嗒。啪嗒。啪嗒。像某種不耐煩的倒計時。", background: Background.Chapter_3_Ch3_Act9_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "13:37。他在心裡記下了這個數字。這是他被帶進這個房間的第七分鐘。", background: Background.Chapter_3_Ch3_Act9_S2 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)計時開始。", background: Background.Chapter_3_Ch3_Act9_S2, portrait: Portrait.GuYan_Determined },
];
